CustomFunction.Calculation:
// Returns "" for the first clause (index = 0),
// " AND " or " OR " for subsequent clauses.
If ( index = 0 ;
	"" ;
// ELSE
	If ( Exact ( boolean ; "or" ) ;
		" OR " ;
	// ELSE
		" AND "
	)
)

// Recursively builds N comma-separated ? placeholders for IN clauses.
// Call with index = 0. Example: count=3 → "?, ?, ?"
If ( index + 1 < count ;
	"?, " & QueryBuildInPlaceholders ( count ; index + 1 ) ;
// ELSE
	"?"
)

// Recursively appends values from a ¶-delimited list to the query's
// bindings array. Call with index = 1 (GetValue is 1-based).
// Used by QueryWhereIn to add N bindings in one pass.
Let
(
[
_bindingCount = JSONGetElement ( query ; "bindingCount" ) ;
_value = GetValue ( values ; index ) ;
_q1 = JSONSetElement ( query ; "bindings[" & _bindingCount & "]" ; _value ; JSONString ) ;
_q2 = JSONSetElement ( _q1 ; "bindingCount" ; _bindingCount + 1 ; JSONNumber )
];
If ( index < valueCount ;
	QueryAppendBindings ( _q2 ; values ; valueCount ; index + 1 ) ;
// ELSE
	_q2
)
)

// Recursively appends bindings from a JSON array (sourceBindings) into
// outerQuery's bindings array. Call with index = 0.
// Analogous to QueryAppendBindings but reads from a JSON array rather
// than a ¶-delimited list. Used by QueryWhereInSubquery.
Let
(
[
_bindingCount = JSONGetElement ( outerQuery ; "bindingCount" ) ;
_value = JSONGetElement ( sourceBindings ; "[" & index & "]" ) ;
_q1 = JSONSetElement ( outerQuery ; "bindings[" & _bindingCount & "]" ; _value ; JSONString ) ;
_q2 = JSONSetElement ( _q1 ; "bindingCount" ; _bindingCount + 1 ; JSONNumber )
];
If ( index + 1 < sourceCount ;
	QueryMergeBindings ( _q2 ; sourceBindings ; sourceCount ; index + 1 ) ;
// ELSE
	_q2
)
)

// Rebuilds outerQuery's bindings array as [prefixBindings...][suffixBindings...].
// prefixBindings is a subquery's bindings JSON array (written first because
// the subquery appears in FROM, before WHERE in SQL). suffixBindings is the
// outer query's existing bindings JSON array. Call with index = 0.
// On the final iteration writes the new bindingCount = prefixCount + suffixCount.
// Used by QueryFromSubquery to ensure correct ? placeholder order.
Let
(
[
_total = prefixCount + suffixCount ;
_value = If ( index < prefixCount ;
	JSONGetElement ( prefixBindings ; "[" & index & "]" ) ;
	JSONGetElement ( suffixBindings ; "[" & ( index - prefixCount ) & "]" )
	) ;
_q1 = JSONSetElement ( outerQuery ; "bindings[" & index & "]" ; _value ; JSONString )
];
If ( index + 1 < _total ;
	QueryPrependBindings ( _q1 ; prefixBindings ; prefixCount ; suffixBindings ; suffixCount ; index + 1 ) ;
// ELSE last element: write final bindingCount
	JSONSetElement ( _q1 ; "bindingCount" ; _total ; JSONNumber )
)
)

// Recursively builds the JOIN clause string.
// Call with index = 0. joins is the raw JSON array from the query object.
// Supported types: inner (default), left, right, cross, subJoin, leftSubJoin.
Let
(
[
_join = JSONGetElement ( joins ; "[" & index & "]" ) ;
_type = JSONGetElement ( _join ; "type" ) ;
_table = JSONGetElement ( _join ; "table" ) ;
_first = JSONGetElement ( _join ; "first" ) ;
_operator = JSONGetElement ( _join ; "operator" ) ;
_second = JSONGetElement ( _join ; "second" ) ;
_keyword = Case (
	Exact ( _type ; "left" ) ; "LEFT JOIN" ;
	Exact ( _type ; "right" ) ; "RIGHT JOIN" ;
	Exact ( _type ; "cross" ) ; "CROSS JOIN" ;
	Exact ( _type ; "subJoin" ) ; "INNER JOIN" ;
	Exact ( _type ; "leftSubJoin" ) ; "LEFT JOIN" ;
	"INNER JOIN"
	) ;
_tableExpr = Case (
	Exact ( _type ; "subJoin" ) or Exact ( _type ; "leftSubJoin" ) ;
		"(" & JSONGetElement ( _join ; "sql" ) & ") " & JSONGetElement ( _join ; "alias" ) ;
	_table
	) ;
_onClause = If ( Exact ( _type ; "cross" ) ;
	"" ;
	" ON " & _first & " " & _operator & " " & _second
	) ;
_clause = _keyword & " " & _tableExpr & _onClause ;
_rest = If ( index + 1 < joinCount ; " " & QueryBuildJoins ( joins ; joinCount ; index + 1 ) ; "" )
];
_clause & _rest
)

// Recursively builds the WHERE clause body (excluding the "WHERE" keyword).
// Call with index = 0. wheres is the raw JSON array from the query object.
// Supported types: basic, in, notIn, null, notNull, between, notBetween,
//   column, raw, group, exists, notExists, inSubquery, notInSubquery.
Let
(
[
_where = JSONGetElement ( wheres ; "[" & index & "]" ) ;
_type = JSONGetElement ( _where ; "type" ) ;
_column = JSONGetElement ( _where ; "column" ) ;
_operator = JSONGetElement ( _where ; "operator" ) ;
_boolean = JSONGetElement ( _where ; "boolean" ) ;
_valueCount = JSONGetElement ( _where ; "valueCount" ) ;
_prefix = QueryBuildWhereBooleanPrefix ( _boolean ; index ) ;
_clause = Case (
	Exact ( _type ; "basic" ) ;
		_prefix & _column & " " & _operator & " ?" ;
	Exact ( _type ; "in" ) ;
		_prefix & _column & " IN (" & QueryBuildInPlaceholders ( _valueCount ; 0 ) & ")" ;
	Exact ( _type ; "notIn" ) ;
		_prefix & _column & " NOT IN (" & QueryBuildInPlaceholders ( _valueCount ; 0 ) & ")" ;
	Exact ( _type ; "null" ) ;
		_prefix & _column & " IS NULL" ;
	Exact ( _type ; "notNull" ) ;
		_prefix & _column & " IS NOT NULL" ;
	Exact ( _type ; "between" ) ;
		_prefix & _column & " BETWEEN ? AND ?" ;
	Exact ( _type ; "notBetween" ) ;
		_prefix & _column & " NOT BETWEEN ? AND ?" ;
	Exact ( _type ; "column" ) ;
		_prefix & _column & " " & _operator & " " & JSONGetElement ( _where ; "second" ) ;
	Exact ( _type ; "raw" ) ;
		_prefix & "(" & JSONGetElement ( _where ; "sql" ) & ")" ;
	Exact ( _type ; "group" ) ;
		_prefix & "(" & QueryBuildWheres ( JSONGetElement ( _where ; "wheres" ) ; JSONGetElement ( _where ; "whereCount" ) ; 0 ) & ")" ;
	Exact ( _type ; "exists" ) ;
		_prefix & "EXISTS (" & JSONGetElement ( _where ; "sql" ) & ")" ;
	Exact ( _type ; "notExists" ) ;
		_prefix & "NOT EXISTS (" & JSONGetElement ( _where ; "sql" ) & ")" ;
	Exact ( _type ; "inSubquery" ) ;
		_prefix & _column & " IN (" & JSONGetElement ( _where ; "sql" ) & ")" ;
	Exact ( _type ; "notInSubquery" ) ;
		_prefix & _column & " NOT IN (" & JSONGetElement ( _where ; "sql" ) & ")" ;
	""
	) ;
_rest = If ( index + 1 < whereCount ; QueryBuildWheres ( wheres ; whereCount ; index + 1 ) ; "" )
];
_clause & _rest
)

// Recursively builds the GROUP BY column list.
// Call with index = 0. groupBys is the raw JSON array from the query object.
// Regular columns are stored as plain JSON strings; raw expressions are stored
// as JSON objects {"type":"raw","sql":"..."} and detected by checking Left(item;1)="{".
// Example output: "\"CONTACT\".\"type\", YEAR(\"Invoice\".\"date\")"
Let
(
[
_item = JSONGetElement ( groupBys ; "[" & index & "]" ) ;
_isObj = Left ( _item ; 1 ) = "{" ;
_type = If ( _isObj ; JSONGetElement ( _item ; "type" ) ; "" ) ;
_col = Case (
	_isObj and Exact ( _type ; "raw" ) ; JSONGetElement ( _item ; "sql" ) ;
	_item
	) ;
_rest = If ( index + 1 < groupByCount ; ", " & QueryBuildGroupBys ( groupBys ; groupByCount ; index + 1 ) ; "" )
];
_col & _rest
)

// Recursively builds the HAVING clause body (excluding the "HAVING" keyword).
// Call with index = 0. havings is the raw JSON array from the query object.
// Supported types: basic (default), raw.
// OR prefix supported via boolean = "or" on any having object.
Let
(
[
_having = JSONGetElement ( havings ; "[" & index & "]" ) ;
_type = JSONGetElement ( _having ; "type" ) ;
_column = JSONGetElement ( _having ; "column" ) ;
_operator = JSONGetElement ( _having ; "operator" ) ;
_boolean = JSONGetElement ( _having ; "boolean" ) ;
_prefix = QueryBuildWhereBooleanPrefix ( _boolean ; index ) ;
_clause = Case (
	Exact ( _type ; "raw" ) ;
		_prefix & "(" & JSONGetElement ( _having ; "sql" ) & ")" ;
	// default: basic column operator ?
	_prefix & _column & " " & _operator & " ?"
	) ;
_rest = If ( index + 1 < havingCount ; QueryBuildHavings ( havings ; havingCount ; index + 1 ) ; "" )
];
_clause & _rest
)

// Recursively builds the ORDER BY column list.
// Call with index = 0. orderBys is the raw JSON array from the query object.
// Supported types: column+direction (default), raw.
// Example output: "\"CONTACT\".\"lastName\" ASC, RAND()"
Let
(
[
_orderBy = JSONGetElement ( orderBys ; "[" & index & "]" ) ;
_type = JSONGetElement ( _orderBy ; "type" ) ;
_clause = Case (
	Exact ( _type ; "raw" ) ;
		JSONGetElement ( _orderBy ; "sql" ) ;
	// default: column direction
	JSONGetElement ( _orderBy ; "column" ) & " " & JSONGetElement ( _orderBy ; "direction" )
	) ;
_rest = If ( index + 1 < orderByCount ; ", " & QueryBuildOrderBys ( orderBys ; orderByCount ; index + 1 ) ; "" )
];
_clause & _rest
)

// Recursively builds the binding argument string for use inside Evaluate().
// Call with index = 0. bindings is the raw JSON array from the query object.
// Each value is wrapped in Quote() to handle special characters safely.
// Example output: "Active" ; "customer" ; "prospect"
// This string is concatenated into the ExecuteSQL Evaluate expression.
Let
(
[
_value = JSONGetElement ( bindings ; "[" & index & "]" ) ;
_quoted = Quote ( _value ) ;
_rest = If ( index + 1 < bindingCount ; " ; " & QueryBuildBindingArgs ( bindings ; bindingCount ; index + 1 ) ; "" )
];
_quoted & _rest
)

// Recursively builds the UNION / UNION ALL clause string.
// Call with index = 0. unions is the raw JSON array from the query object.
// Each union item: {"sql": "SELECT ...", "all": true|false}
// UNION removes duplicates; UNION ALL keeps them.
Let
(
[
_union = JSONGetElement ( unions ; "[" & index & "]" ) ;
_sql = JSONGetElement ( _union ; "sql" ) ;
_all = JSONGetElement ( _union ; "all" ) ;
_keyword = If ( not IsEmpty ( _all ) and _all ; " UNION ALL " ; " UNION " ) ;
_clause = _keyword & _sql ;
_rest = If ( index + 1 < unionCount ; QueryBuildUnions ( unions ; unionCount ; index + 1 ) ; "" )
];
_clause & _rest
)

// Recursively converts a ¶-delimited column list to SQL column expressions.
// Delegates individual field conversion to QueryFieldFormat.
// Other expressions (*, COUNT(*), already-dotted names, etc.) pass through unchanged.
// Call with index = 1 (GetValue is 1-based).
Let
(
[
_field = Trim ( GetValue ( columns ; index ) ) ;
_converted = QueryFieldFormat ( _field ) ;
_rest = If ( index < columnCount ;
	", " & QueryBuildSelects ( columns ; columnCount ; index + 1 ) ;
// ELSE
	""
	)
];
_converted & _rest
)

// Converts a FileMaker fully-qualified field name (Table::Field) to a
// quoted SQL dot-notation identifier ("Table"."Field"). Quote() is used for
// readability and automatic escaping. Expressions without :: pass through
// unchanged, so *, COUNT(*), and already-converted references are safe.
// Callers are responsible for resolving direct field references via GetFieldName()
// before passing to this function.
Let
(
[
_sepPos = Position ( field ; "::" ; 1 ; 1 )
];
If ( _sepPos > 0 ;
	Quote ( Left ( field ; _sepPos - 1 ) ) & "." & Quote ( Middle ( field ; _sepPos + 2 ; Length ( field ) ) ) ;
// ELSE
	field
)
)

// Recursively extracts a plain key name from each column expression in a
// ¶-delimited list, for use as JSON object property names.
// Extraction rules (applied to the original input before SQL conversion):
//   Table::Field  →  Field   (FM fully-qualified: take part after ::)
//   Table.field   →  field   (dot notation: take part after the dot)
//   anything else →  as-is   (e.g. *, COUNT(*))
// Call with index = 1.
Let
(
[
_expr = Trim ( GetValue ( columns ; index ) ) ;
_scopePos = Position ( _expr ; "::" ; 1 ; 1 ) ;
_dotPos = Position ( _expr ; "." ; 1 ; 1 ) ;
_key = Case (
	_scopePos > 0 ; Middle ( _expr ; _scopePos + 2 ; Length ( _expr ) ) ;
	_dotPos > 0 ; Middle ( _expr ; _dotPos + 1 ; Length ( _expr ) ) ;
	_expr
	) ;
_rest = If ( index < columnCount ;
	"¶" & QueryBuildSelectKeys ( columns ; columnCount ; index + 1 ) ;
// ELSE
	""
	)
];
_key & _rest
)

// Recursively builds a single JSON object from parallel ¶-delimited lists
// of field values and key names. Call with index = 1 and obj = "{}".
// All values are stored as JSONString; numeric/date coercion is left to the caller.
Let
(
[
_key = GetValue ( keys ; index ) ;
_value = GetValue ( fields ; index ) ;
_newObj = JSONSetElement ( obj ; _key ; _value ; JSONString )
];
If ( index < keyCount ;
	QueryBuildJsonRow ( _newObj ; fields ; keys ; keyCount ; index + 1 ) ;
// ELSE
	_newObj
)
)

// Recursively appends row objects to a JSON array.
// rawResult is the ExecuteSQL output with Char(28) field separators and ¶ row separators.
// Call with rowIndex = 1 and result = "[]".
Let
(
[
_rawRow = GetValue ( rawResult ; rowIndex ) ;
_fields = Substitute ( _rawRow ; Char ( 28 ) ; "¶" ) ;
_rowObj = QueryBuildJsonRow ( "{}" ; _fields ; keys ; keyCount ; 1 ) ;
_newResult = JSONSetElement ( result ; "[" & ( rowIndex - 1 ) & "]" ; _rowObj ; JSONObject )
];
If ( rowIndex < rowCount ;
	QueryBuildJsonRows ( _newResult ; rawResult ; rowCount ; keys ; keyCount ; rowIndex + 1 ) ;
// ELSE
	_newResult
)
)

Let
(
[
_fqName = GetFieldName ( table ) ;
_tableName = If ( Position ( _fqName ; "::" ; 1 ; 1 ) > 0 ; _fqName ; table ) ;
_table = Quote (
	If ( PatternCount ( _tableName ; "::" ) ;
		Left ( _tableName ; Position ( _tableName ; "::" ; 1 ; 1 ) - 1 ) ;
	// ELSE
		_tableName
	))
];
JSONSetElement ( "{}" ;
[ "table" ; _table ; JSONString ] ;
[ "selects" ; "*" ; JSONString ] ;
[ "selectKeys" ; "*" ; JSONString ] ;
[ "joins" ; "[]" ; JSONRaw ] ;
[ "joinCount" ; 0 ; JSONNumber ] ;
[ "wheres" ; "[]" ; JSONRaw ] ;
[ "whereCount" ; 0 ; JSONNumber ] ;
[ "groupBys" ; "[]" ; JSONRaw ] ;
[ "groupByCount" ; 0 ; JSONNumber ] ;
[ "havings" ; "[]" ; JSONRaw ] ;
[ "havingCount" ; 0 ; JSONNumber ] ;
[ "orderBys" ; "[]" ; JSONRaw ] ;
[ "orderByCount" ; 0 ; JSONNumber ] ;
[ "limit" ; "" ; JSONString ] ;
[ "offset" ; "" ; JSONString ] ;
[ "bindings" ; "[]" ; JSONRaw ] ;
[ "bindingCount" ; 0 ; JSONNumber ]
)
)

// Accepts a ¶-delimited list (e.g. from List() / GetFieldName()) or a
// comma-separated string. FileMaker fully-qualified names (Table::Field) are
// converted to quoted SQL dot notation ("Table"."Field"). Other expressions
// (*, COUNT(*), already-dotted names, raw SQL expressions, etc.) pass through
// unchanged — no separate QuerySelectRaw is needed.
// Calls are additive: the first call after QueryNew replaces the initial
// "*" sentinel; subsequent calls append to the existing column list.
Let
(
[
_normalized = Substitute ( Substitute ( columns ; ", " ; "¶" ) ; "," ; "¶" ) ;
_columnCount = ValueCount ( _normalized ) ;
_newSelects = QueryBuildSelects ( _normalized ; _columnCount ; 1 ) ;
_newKeys = QueryBuildSelectKeys ( _normalized ; _columnCount ; 1 ) ;
_existingSelects = JSONGetElement ( query ; "selects" ) ;
_existingKeys = JSONGetElement ( query ; "selectKeys" ) ;
_isWildcard = Exact ( _existingSelects ; "*" ) ;
_finalSelects = If ( _isWildcard ; _newSelects ; _existingSelects & ", " & _newSelects ) ;
_finalKeys = If ( _isWildcard ; _newKeys ; _existingKeys & ¶ & _newKeys ) ;
_q1 = JSONSetElement ( query ; "selects" ; _finalSelects ; JSONString )
];
JSONSetElement ( _q1 ; "selectKeys" ; _finalKeys ; JSONString )
)

// Adds a subquery expression to the SELECT list: (SELECT ...) AS alias.
// alias is a plain SQL identifier string (e.g. "totalAmount").
// The subquery's bindings are prepended to the outer query's bindings because
// the SELECT clause appears before WHERE in SQL, so its ? placeholders must
// come first in the bindings array. Call this before adding WHERE conditions
// if the subquery itself has bindings.
// NOTE: Subqueries in SELECT require FileMaker 17+.
Let
(
[
_subSql = QueryToSQL ( subquery ) ;
_subBindings = JSONGetElement ( subquery ; "bindings" ) ;
_subBindingCount = JSONGetElement ( subquery ; "bindingCount" ) ;
_subExpr = "(" & _subSql & ") AS " & Quote ( alias ) ;
_existingSelects = JSONGetElement ( query ; "selects" ) ;
_existingKeys = JSONGetElement ( query ; "selectKeys" ) ;
_isWildcard = Exact ( _existingSelects ; "*" ) ;
_finalSelects = If ( _isWildcard ; _subExpr ; _existingSelects & ", " & _subExpr ) ;
_finalKeys = If ( _isWildcard ; alias ; _existingKeys & ¶ & alias ) ;
_outerBindings = JSONGetElement ( query ; "bindings" ) ;
_outerBindingCount = JSONGetElement ( query ; "bindingCount" ) ;
_q1 = JSONSetElement ( query ; "selects" ; _finalSelects ; JSONString ) ;
_q2 = JSONSetElement ( _q1 ; "selectKeys" ; _finalKeys ; JSONString ) ;
_q3 = If ( _subBindingCount > 0 ;
	QueryPrependBindings ( _q2 ; _subBindings ; _subBindingCount ; _outerBindings ; _outerBindingCount ; 0 ) ;
	_q2
	)
];
_q3
)

Let
(
[
_whereCount = JSONGetElement ( query ; "whereCount" ) ;
_bindingCount = JSONGetElement ( query ; "bindingCount" ) ;
_fqName = GetFieldName ( column ) ;
_col = If ( Position ( _fqName ; "::" ; 1 ; 1 ) > 0 ; _fqName ; column ) ;
_column = QueryFieldFormat ( _col ) ;
_whereObj = JSONSetElement ( "{}" ;
	[ "type" ; "basic" ; JSONString ] ;
	[ "column" ; _column ; JSONString ] ;
	[ "operator" ; operator ; JSONString ] ;
	[ "boolean" ; "and" ; JSONString ]
	) ;
_q1 = JSONSetElement ( query ; "wheres[" & _whereCount & "]" ; _whereObj ; JSONObject ) ;
_q2 = JSONSetElement ( _q1 ; "whereCount" ; _whereCount + 1 ; JSONNumber ) ;
_q3 = JSONSetElement ( _q2 ; "bindings[" & _bindingCount & "]" ; value ; JSONString ) ;
_q4 = JSONSetElement ( _q3 ; "bindingCount" ; _bindingCount + 1 ; JSONNumber )
];
_q4
)

Let
(
[
_whereCount = JSONGetElement ( query ; "whereCount" ) ;
_bindingCount = JSONGetElement ( query ; "bindingCount" ) ;
_fqName = GetFieldName ( column ) ;
_col = If ( Position ( _fqName ; "::" ; 1 ; 1 ) > 0 ; _fqName ; column ) ;
_column = QueryFieldFormat ( _col ) ;
_whereObj = JSONSetElement ( "{}" ;
	[ "type" ; "basic" ; JSONString ] ;
	[ "column" ; _column ; JSONString ] ;
	[ "operator" ; operator ; JSONString ] ;
	[ "boolean" ; "or" ; JSONString ]
	) ;
_q1 = JSONSetElement ( query ; "wheres[" & _whereCount & "]" ; _whereObj ; JSONObject ) ;
_q2 = JSONSetElement ( _q1 ; "whereCount" ; _whereCount + 1 ; JSONNumber ) ;
_q3 = JSONSetElement ( _q2 ; "bindings[" & _bindingCount & "]" ; value ; JSONString ) ;
_q4 = JSONSetElement ( _q3 ; "bindingCount" ; _bindingCount + 1 ; JSONNumber )
];
_q4
)

// values is a ¶-delimited list of values.
// Appends an IN where clause and N bindings (one per value).
Let
(
[
_whereCount = JSONGetElement ( query ; "whereCount" ) ;
_valueCount = ValueCount ( values ) ;
_fqName = GetFieldName ( column ) ;
_col = If ( Position ( _fqName ; "::" ; 1 ; 1 ) > 0 ; _fqName ; column ) ;
_column = QueryFieldFormat ( _col ) ;
_whereObj = JSONSetElement ( "{}" ;
	[ "type" ; "in" ; JSONString ] ;
	[ "column" ; _column ; JSONString ] ;
	[ "valueCount" ; _valueCount ; JSONNumber ] ;
	[ "boolean" ; "and" ; JSONString ]
	) ;
_q1 = JSONSetElement ( query ; "wheres[" & _whereCount & "]" ; _whereObj ; JSONObject ) ;
_q2 = JSONSetElement ( _q1 ; "whereCount" ; _whereCount + 1 ; JSONNumber ) ;
_q3 = QueryAppendBindings ( _q2 ; values ; _valueCount ; 1 )
];
_q3
)

// values is a ¶-delimited list of values.
// Appends AND column NOT IN (?, ?, ...) and N bindings (one per value).
Let
(
[
_whereCount = JSONGetElement ( query ; "whereCount" ) ;
_valueCount = ValueCount ( values ) ;
_fqName = GetFieldName ( column ) ;
_col = If ( Position ( _fqName ; "::" ; 1 ; 1 ) > 0 ; _fqName ; column ) ;
_column = QueryFieldFormat ( _col ) ;
_whereObj = JSONSetElement ( "{}" ;
	[ "type" ; "notIn" ; JSONString ] ;
	[ "column" ; _column ; JSONString ] ;
	[ "valueCount" ; _valueCount ; JSONNumber ] ;
	[ "boolean" ; "and" ; JSONString ]
	) ;
_q1 = JSONSetElement ( query ; "wheres[" & _whereCount & "]" ; _whereObj ; JSONObject ) ;
_q2 = JSONSetElement ( _q1 ; "whereCount" ; _whereCount + 1 ; JSONNumber ) ;
_q3 = QueryAppendBindings ( _q2 ; values ; _valueCount ; 1 )
];
_q3
)

// values is a ¶-delimited list of values.
// Appends OR column IN (?, ?, ...) and N bindings (one per value).
Let
(
[
_whereCount = JSONGetElement ( query ; "whereCount" ) ;
_valueCount = ValueCount ( values ) ;
_fqName = GetFieldName ( column ) ;
_col = If ( Position ( _fqName ; "::" ; 1 ; 1 ) > 0 ; _fqName ; column ) ;
_column = QueryFieldFormat ( _col ) ;
_whereObj = JSONSetElement ( "{}" ;
	[ "type" ; "in" ; JSONString ] ;
	[ "column" ; _column ; JSONString ] ;
	[ "valueCount" ; _valueCount ; JSONNumber ] ;
	[ "boolean" ; "or" ; JSONString ]
	) ;
_q1 = JSONSetElement ( query ; "wheres[" & _whereCount & "]" ; _whereObj ; JSONObject ) ;
_q2 = JSONSetElement ( _q1 ; "whereCount" ; _whereCount + 1 ; JSONNumber ) ;
_q3 = QueryAppendBindings ( _q2 ; values ; _valueCount ; 1 )
];
_q3
)

Let
(
[
_whereCount = JSONGetElement ( query ; "whereCount" ) ;
_fqName = GetFieldName ( column ) ;
_col = If ( Position ( _fqName ; "::" ; 1 ; 1 ) > 0 ; _fqName ; column ) ;
_column = QueryFieldFormat ( _col ) ;
_whereObj = JSONSetElement ( "{}" ;
	[ "type" ; "null" ; JSONString ] ;
	[ "column" ; _column ; JSONString ] ;
	[ "boolean" ; "and" ; JSONString ]
	)
];
JSONSetElement (
	JSONSetElement ( query ; "wheres[" & _whereCount & "]" ; _whereObj ; JSONObject ) ;
	"whereCount" ; _whereCount + 1 ; JSONNumber
)
)

Let
(
[
_whereCount = JSONGetElement ( query ; "whereCount" ) ;
_fqName = GetFieldName ( column ) ;
_col = If ( Position ( _fqName ; "::" ; 1 ; 1 ) > 0 ; _fqName ; column ) ;
_column = QueryFieldFormat ( _col ) ;
_whereObj = JSONSetElement ( "{}" ;
	[ "type" ; "notNull" ; JSONString ] ;
	[ "column" ; _column ; JSONString ] ;
	[ "boolean" ; "and" ; JSONString ]
	)
];
JSONSetElement (
	JSONSetElement ( query ; "wheres[" & _whereCount & "]" ; _whereObj ; JSONObject ) ;
	"whereCount" ; _whereCount + 1 ; JSONNumber
)
)

// Appends OR column IS NULL.
Let
(
[
_whereCount = JSONGetElement ( query ; "whereCount" ) ;
_fqName = GetFieldName ( column ) ;
_col = If ( Position ( _fqName ; "::" ; 1 ; 1 ) > 0 ; _fqName ; column ) ;
_column = QueryFieldFormat ( _col ) ;
_whereObj = JSONSetElement ( "{}" ;
	[ "type" ; "null" ; JSONString ] ;
	[ "column" ; _column ; JSONString ] ;
	[ "boolean" ; "or" ; JSONString ]
	)
];
JSONSetElement (
	JSONSetElement ( query ; "wheres[" & _whereCount & "]" ; _whereObj ; JSONObject ) ;
	"whereCount" ; _whereCount + 1 ; JSONNumber
)
)

// Appends OR column IS NOT NULL.
Let
(
[
_whereCount = JSONGetElement ( query ; "whereCount" ) ;
_fqName = GetFieldName ( column ) ;
_col = If ( Position ( _fqName ; "::" ; 1 ; 1 ) > 0 ; _fqName ; column ) ;
_column = QueryFieldFormat ( _col ) ;
_whereObj = JSONSetElement ( "{}" ;
	[ "type" ; "notNull" ; JSONString ] ;
