_groupBindingCount = JSONGetElement ( groupedQuery ; "bindingCount" ) ;
_whereObj = JSONSetElement ( "{}" ;
	[ "type" ; "group" ; JSONString ] ;
	[ "wheres" ; _groupWheres ; JSONRaw ] ;
	[ "whereCount" ; _groupWhereCount ; JSONNumber ] ;
	[ "boolean" ; "and" ; JSONString ]
	) ;
_q1 = JSONSetElement ( query ; "wheres[" & _whereCount & "]" ; _whereObj ; JSONObject ) ;
_q2 = JSONSetElement ( _q1 ; "whereCount" ; _whereCount + 1 ; JSONNumber ) ;
