)

// Clears all ORDER BY clauses from the query.
// After calling this, new ORDER BY clauses can be added with QueryOrderBy.
JSONSetElement (
	JSONSetElement ( query ; "orderBys" ; "[]" ; JSONRaw ) ;
	"orderByCount" ; 0 ; JSONNumber
)

Let
(
[
_groupByCount = JSONGetElement ( query ; "groupByCount" ) ;
_fqName = GetFieldName ( column ) ;
_col = If ( Position ( _fqName ; "::" ; 1 ; 1 ) > 0 ; _fqName ; column ) ;
_column = QueryFieldFormat ( _col )
];
JSONSetElement (
	JSONSetElement ( query ; "groupBys[" & _groupByCount & "]" ; _column ; JSONString ) ;
	"groupByCount" ; _groupByCount + 1 ; JSONNumber
)
)

// Appends a raw SQL expression to the GROUP BY clause verbatim.
// Useful for function-based grouping such as YEAR(dateField).
// Example: QueryGroupByRaw ( query ; "YEAR(\"Invoice\".\"date\")" )
Let
(
[
_groupByCount = JSONGetElement ( query ; "groupByCount" ) ;
_rawObj = JSONSetElement ( "{}" ;
	[ "type" ; "raw" ; JSONString ] ;
	[ "sql" ; rawSql ; JSONString ]
	)
];
JSONSetElement (
	JSONSetElement ( query ; "groupBys[" & _groupByCount & "]" ; _rawObj ; JSONObject ) ;
	"groupByCount" ; _groupByCount + 1 ; JSONNumber
)
)

Let
(
[
_havingCount = JSONGetElement ( query ; "havingCount" ) ;
_bindingCount = JSONGetElement ( query ; "bindingCount" ) ;
_fqName = GetFieldName ( column ) ;
_col = If ( Position ( _fqName ; "::" ; 1 ; 1 ) > 0 ; _fqName ; column ) ;
_column = QueryFieldFormat ( _col ) ;
_havingObj = JSONSetElement ( "{}" ;
	[ "column" ; _column ; JSONString ] ;
	[ "operator" ; operator ; JSONString ] ;
	[ "boolean" ; "and" ; JSONString ]
	) ;
_q1 = JSONSetElement ( query ; "havings[" & _havingCount & "]" ; _havingObj ; JSONObject ) ;
_q2 = JSONSetElement ( _q1 ; "havingCount" ; _havingCount + 1 ; JSONNumber ) ;
_q3 = JSONSetElement ( _q2 ; "bindings[" & _bindingCount & "]" ; value ; JSONString ) ;
_q4 = JSONSetElement ( _q3 ; "bindingCount" ; _bindingCount + 1 ; JSONNumber )
];
_q4
)

// Appends OR column operator value to the HAVING clause. One binding is added.
// Must be used after QueryGroupBy.
// Use QueryHaving for AND HAVING.
Let
(
[
_havingCount = JSONGetElement ( query ; "havingCount" ) ;
_bindingCount = JSONGetElement ( query ; "bindingCount" ) ;
_fqName = GetFieldName ( column ) ;
_col = If ( Position ( _fqName ; "::" ; 1 ; 1 ) > 0 ; _fqName ; column ) ;
_column = QueryFieldFormat ( _col ) ;
_havingObj = JSONSetElement ( "{}" ;
	[ "column" ; _column ; JSONString ] ;
	[ "operator" ; operator ; JSONString ] ;
	[ "boolean" ; "or" ; JSONString ]
	) ;
_q1 = JSONSetElement ( query ; "havings[" & _havingCount & "]" ; _havingObj ; JSONObject ) ;
_q2 = JSONSetElement ( _q1 ; "havingCount" ; _havingCount + 1 ; JSONNumber ) ;
_q3 = JSONSetElement ( _q2 ; "bindings[" & _bindingCount & "]" ; value ; JSONString ) ;
_q4 = JSONSetElement ( _q3 ; "bindingCount" ; _bindingCount + 1 ; JSONNumber )
];
_q4
)

// Appends AND (rawSql) to the HAVING clause verbatim.
// bindings is an optional ¶-delimited list of values for any ? placeholders in rawSql.
// Leave bindings empty if rawSql contains no placeholders.
// Use QueryOrHavingRaw for OR prefix.
Let
(
[
_havingCount = JSONGetElement ( query ; "havingCount" ) ;
_valueCount = If ( IsEmpty ( bindings ) ; 0 ; ValueCount ( bindings ) ) ;
_havingObj = JSONSetElement ( "{}" ;
	[ "type" ; "raw" ; JSONString ] ;
	[ "sql" ; rawSql ; JSONString ] ;
	[ "boolean" ; "and" ; JSONString ]
	) ;
_q1 = JSONSetElement ( query ; "havings[" & _havingCount & "]" ; _havingObj ; JSONObject ) ;
_q2 = JSONSetElement ( _q1 ; "havingCount" ; _havingCount + 1 ; JSONNumber ) ;
_q3 = If ( _valueCount > 0 ;
	QueryAppendBindings ( _q2 ; bindings ; _valueCount ; 1 ) ;
	_q2
	)
];
_q3
)

// Appends OR (rawSql) to the HAVING clause verbatim.
// bindings is an optional ¶-delimited list of values for any ? placeholders in rawSql.
// Leave bindings empty if rawSql contains no placeholders.
// Use QueryHavingRaw for AND prefix.
Let
(
[
_havingCount = JSONGetElement ( query ; "havingCount" ) ;
_valueCount = If ( IsEmpty ( bindings ) ; 0 ; ValueCount ( bindings ) ) ;
_havingObj = JSONSetElement ( "{}" ;
	[ "type" ; "raw" ; JSONString ] ;
	[ "sql" ; rawSql ; JSONString ] ;
	[ "boolean" ; "or" ; JSONString ]
	) ;
_q1 = JSONSetElement ( query ; "havings[" & _havingCount & "]" ; _havingObj ; JSONObject ) ;
_q2 = JSONSetElement ( _q1 ; "havingCount" ; _havingCount + 1 ; JSONNumber ) ;
_q3 = If ( _valueCount > 0 ;
	QueryAppendBindings ( _q2 ; bindings ; _valueCount ; 1 ) ;
	_q2
	)
];
_q3
)

// Convenience function: sets LIMIT and OFFSET for a specific page number.
// page is 1-based. Equivalent to:
//   QueryLimit ( QueryOffset ( query ; (page - 1) * perPage ) ; perPage )
// Example: page=2, perPage=25 → FETCH FIRST 25 ROWS ONLY OFFSET 25 ROWS
Let
(
[
_offset = ( page - 1 ) * perPage ;
_q1 = JSONSetElement ( query ; "limit" ; perPage ; JSONNumber ) ;
_q2 = JSONSetElement ( _q1 ; "offset" ; _offset ; JSONNumber )
];
_q2
)

// Replaces the FROM table with a derived table: FROM (SELECT ...) alias.
// The table name set in QueryNew is discarded and replaced by the subquery
// expression. alias is a plain SQL identifier — use a simple string like "sub".
// The subquery's bindings are prepended to any existing outer bindings because
// the FROM clause appears before WHERE in the SQL string, so its ? placeholders
// must come first in the bindings array for ExecuteSQL to match them correctly.
// NOTE: Derived tables (subqueries in FROM) are functional in FileMaker 19.x
// but are not formally documented by Claris. Test in your target FM version.
// Avoid QueryLimit / QueryOffset on the inner query — FETCH FIRST inside
// a subquery is not supported in all FM versions.
Let
(
[
_subSql = QueryToSQL ( subquery ) ;
_derivedTable = "(" & _subSql & ") " & alias ;
_subBindings = JSONGetElement ( subquery ; "bindings" ) ;
_subBindingCount = JSONGetElement ( subquery ; "bindingCount" ) ;
_outerBindings = JSONGetElement ( outerQuery ; "bindings" ) ;
_outerBindingCount = JSONGetElement ( outerQuery ; "bindingCount" ) ;
_q1 = JSONSetElement ( outerQuery ; "table" ; _derivedTable ; JSONString ) ;
_q2 = If ( _subBindingCount > 0 ;
	QueryPrependBindings ( _q1 ; _subBindings ; _subBindingCount ; _outerBindings ; _outerBindingCount ; 0 ) ;
	_q1
	)
];
_q2
)

// Appends a UNION or UNION ALL clause combining two query results.
// unionQuery is a fully-assembled fmorm query object.
// all: pass 1 for UNION ALL (keeps duplicates), 0 for UNION (removes duplicates).
// The union query's bindings are appended after the main query's bindings.
// NOTE: UNION requires FileMaker 17+. Both queries must select the same number
// of columns. ORDER BY on the combined result is not supported by all FM versions.
Let
(
[
_unionCount = If ( IsEmpty ( JSONGetElement ( query ; "unionCount" ) ) ; 0 ; JSONGetElement ( query ; "unionCount" ) ) ;
_subSql = QueryToSQL ( unionQuery ) ;
_subBindings = JSONGetElement ( unionQuery ; "bindings" ) ;
_subBindingCount = JSONGetElement ( unionQuery ; "bindingCount" ) ;
_unionObj = JSONSetElement ( "{}" ;
	[ "sql" ; _subSql ; JSONString ] ;
	[ "all" ; not IsEmpty ( all ) and all ; JSONBoolean ]
	) ;
_q1 = JSONSetElement ( query ; "unions[" & _unionCount & "]" ; _unionObj ; JSONObject ) ;
_q2 = JSONSetElement ( _q1 ; "unionCount" ; _unionCount + 1 ; JSONNumber ) ;
_q3 = If ( _subBindingCount > 0 ;
	QueryMergeBindings ( _q2 ; _subBindings ; _subBindingCount ; 0 ) ;
	_q2
	)
];
_q3
)

// Assembles and returns the full SQL string without executing it.
// Useful for debugging. Bindings are represented as ? placeholders.
// Output is pretty-printed: each major clause on its own line,
// child items (fields, conditions, columns) indented with 4 spaces.
Let
(
[
_table = JSONGetElement ( query ; "table" ) ;
_selects = JSONGetElement ( query ; "selects" ) ;
_distinct = JSONGetElement ( query ; "distinct" ) ;
_joins = JSONGetElement ( query ; "joins" ) ;
_joinCount = JSONGetElement ( query ; "joinCount" ) ;
_wheres = JSONGetElement ( query ; "wheres" ) ;
_whereCount = JSONGetElement ( query ; "whereCount" ) ;
_groupBys = JSONGetElement ( query ; "groupBys" ) ;
_groupByCount = JSONGetElement ( query ; "groupByCount" ) ;
_havings = JSONGetElement ( query ; "havings" ) ;
_havingCount = JSONGetElement ( query ; "havingCount" ) ;
_orderBys = JSONGetElement ( query ; "orderBys" ) ;
_orderByCount = JSONGetElement ( query ; "orderByCount" ) ;
_limit = JSONGetElement ( query ; "limit" ) ;
_offset = JSONGetElement ( query ; "offset" ) ;
_unions = JSONGetElement ( query ; "unions" ) ;
_unionCount = JSONGetElement ( query ; "unionCount" ) ;
_in = "    " ;
_selectKeyword = If ( not IsEmpty ( _distinct ) and _distinct ; "SELECT DISTINCT" ; "SELECT" ) ;
_selectFields = Substitute ( _selects ; ", " ; "," & ¶ & _in ) ;
_joinRaw = If ( _joinCount > 0 ; QueryBuildJoins ( _joins ; _joinCount ; 0 ) ; "" ) ;
_joinSplit = Substitute ( Substitute ( Substitute ( Substitute ( _joinRaw ;
	" INNER JOIN " ; ¶ & "INNER JOIN " ) ;
	" LEFT JOIN " ; ¶ & "LEFT JOIN " ) ;
	" RIGHT JOIN " ; ¶ & "RIGHT JOIN " ) ;
	" CROSS JOIN " ; ¶ & "CROSS JOIN " ) ;
_joinClause = If ( _joinCount > 0 ;
	¶ & Substitute ( Substitute ( Substitute ( Substitute ( _joinSplit ;
		"INNER JOIN " ; "INNER JOIN" & ¶ & _in ) ;
		"LEFT JOIN " ; "LEFT JOIN" & ¶ & _in ) ;
		"RIGHT JOIN " ; "RIGHT JOIN" & ¶ & _in ) ;
		"CROSS JOIN " ; "CROSS JOIN" & ¶ & _in ) ;
	""
) ;
_whereRaw = If ( _whereCount > 0 ; QueryBuildWheres ( _wheres ; _whereCount ; 0 ) ; "" ) ;
_whereClause = If ( _whereCount > 0 ;
	¶ & "WHERE" & ¶ & _in & Substitute ( Substitute ( _whereRaw ; " AND " ; ¶ & _in & "AND" & ¶ & _in ) ; " OR " ; ¶ & _in & "OR" & ¶ & _in ) ;
	""
) ;
_groupByRaw = If ( _groupByCount > 0 ; QueryBuildGroupBys ( _groupBys ; _groupByCount ; 0 ) ; "" ) ;
_groupByClause = If ( _groupByCount > 0 ;
	¶ & "GROUP BY" & ¶ & _in & Substitute ( _groupByRaw ; ", " ; "," & ¶ & _in ) ;
	""
) ;
_havingRaw = If ( _havingCount > 0 ; QueryBuildHavings ( _havings ; _havingCount ; 0 ) ; "" ) ;
_havingClause = If ( _havingCount > 0 ;
	¶ & "HAVING" & ¶ & _in & Substitute ( Substitute ( _havingRaw ; " AND " ; ¶ & _in & "AND" & ¶ & _in ) ; " OR " ; ¶ & _in & "OR" & ¶ & _in ) ;
	""
) ;
_orderByRaw = If ( _orderByCount > 0 ; QueryBuildOrderBys ( _orderBys ; _orderByCount ; 0 ) ; "" ) ;
_orderByClause = If ( _orderByCount > 0 ;
	¶ & "ORDER BY" & ¶ & _in & Substitute ( _orderByRaw ; ", " ; "," & ¶ & _in ) ;
	""
) ;
_offsetClause = If ( not IsEmpty ( _offset ) ; ¶ & "OFFSET " & _offset & " ROWS" ; "" ) ;
_limitClause = If ( not IsEmpty ( _limit ) ; ¶ & "FETCH FIRST " & _limit & " ROWS ONLY" ; "" ) ;
_unionClause = If ( not IsEmpty ( _unionCount ) and _unionCount > 0 ;
	QueryBuildUnions ( _unions ; _unionCount ; 0 ) ;
	""
)
];
_selectKeyword & ¶ & _in & _selectFields &
¶ & "FROM" & ¶ & _in & _table &
_joinClause &
_whereClause &
_groupByClause &
_havingClause &
_orderByClause &
_offsetClause &
_limitClause &
_unionClause
)

// Executes the assembled query via ExecuteSQL using Evaluate to
// dynamically bind the stored parameter values.
// Returns "" if ExecuteSQL returns an error (result starting with "?").
Let
(
[
_sql = QueryToSQL ( query ) ;
_bindings = JSONGetElement ( query ; "bindings" ) ;
_bindingCount = JSONGetElement ( query ; "bindingCount" ) ;
_bindingArgs = QueryBuildBindingArgs ( _bindings ; _bindingCount ; 0 ) ;
_exprBase = "ExecuteSQL ( " & Quote ( _sql ) & " ; " & Quote ( fieldSeparator ) & " ; " & Quote ( rowSeparator ) ;
_expr = _exprBase & If ( _bindingCount > 0 ; " ; " & _bindingArgs ; "" ) & " )" ;
_result = Evaluate ( _expr )
];
If ( Left ( _result ; 1 ) = "?" ; "" ; _result )
)

// Executes the query and returns results as a JSON array of objects.
// Property names are derived automatically from the selectKeys stored in the
// query object, which QuerySelect populates from the original column input.
// Returns "[]" when the query produces no rows or an error.
Let
(
[
_keys = JSONGetElement ( query ; "selectKeys" ) ;
_keyCount = ValueCount ( _keys ) ;
_rawResult = QueryGet ( query ; Char ( 28 ) ; "¶" ) ;
_rowCount = If ( IsEmpty ( _rawResult ) ; 0 ; ValueCount ( _rawResult ) )
];
If ( _rowCount = 0 ;
	"[]" ;
// ELSE
	QueryBuildJsonRows ( "[]" ; _rawResult ; _rowCount ; _keys ; _keyCount ; 1 )
)
)

// Executes SELECT COUNT(*) for the assembled query and returns the count as a number.
// The original query object is not modified.
// Returns 0 on error or empty result.
Let
(
[
_q = JSONSetElement ( query ; "selects" ; "COUNT(*)" ; JSONString ) ;
_result = QueryGet ( _q ; ¶ ; Char ( 28 ) )
];
GetAsNumber ( GetValue ( _result ; 1 ) )
)

// Executes SELECT SUM(column) for the assembled query and returns the sum as a number.
// column accepts Table::Field references, GetFieldName() strings, or SQL expressions.
// The original query object is not modified.
// Returns 0 on error or empty result.
Let
(
[
_fqName = GetFieldName ( column ) ;
_col = If ( Position ( _fqName ; "::" ; 1 ; 1 ) > 0 ; _fqName ; column ) ;
_column = QueryFieldFormat ( _col ) ;
_q = JSONSetElement ( query ; "selects" ; "SUM(" & _column & ")" ; JSONString ) ;
_result = QueryGet ( _q ; ¶ ; Char ( 28 ) )
];
GetAsNumber ( GetValue ( _result ; 1 ) )
)

// Executes SELECT AVG(column) for the assembled query and returns the average as a number.
// column accepts Table::Field references, GetFieldName() strings, or SQL expressions.
// The original query object is not modified.
// Returns 0 on error or empty result.
Let
(
[
_fqName = GetFieldName ( column ) ;
_col = If ( Position ( _fqName ; "::" ; 1 ; 1 ) > 0 ; _fqName ; column ) ;
_column = QueryFieldFormat ( _col ) ;
_q = JSONSetElement ( query ; "selects" ; "AVG(" & _column & ")" ; JSONString ) ;
_result = QueryGet ( _q ; ¶ ; Char ( 28 ) )
];
GetAsNumber ( GetValue ( _result ; 1 ) )
)

// Executes SELECT MAX(column) for the assembled query and returns the maximum value.
// column accepts Table::Field references, GetFieldName() strings, or SQL expressions.
// The original query object is not modified.
// Returns "" on error or empty result.
Let
(
[
_fqName = GetFieldName ( column ) ;
_col = If ( Position ( _fqName ; "::" ; 1 ; 1 ) > 0 ; _fqName ; column ) ;
_column = QueryFieldFormat ( _col ) ;
_q = JSONSetElement ( query ; "selects" ; "MAX(" & _column & ")" ; JSONString ) ;
_result = QueryGet ( _q ; ¶ ; Char ( 28 ) )
];
GetValue ( _result ; 1 )
)

// Executes SELECT MIN(column) for the assembled query and returns the minimum value.
// column accepts Table::Field references, GetFieldName() strings, or SQL expressions.
// The original query object is not modified.
// Returns "" on error or empty result.
Let
(
[
_fqName = GetFieldName ( column ) ;
_col = If ( Position ( _fqName ; "::" ; 1 ; 1 ) > 0 ; _fqName ; column ) ;
_column = QueryFieldFormat ( _col ) ;
_q = JSONSetElement ( query ; "selects" ; "MIN(" & _column & ")" ; JSONString ) ;
_result = QueryGet ( _q ; ¶ ; Char ( 28 ) )
];
GetValue ( _result ; 1 )
)

// Conditionally applies query modifications. Returns queryIfTrue when condition
// is true (non-zero, non-empty), otherwise returns the original query unchanged.
// Both query paths are evaluated by FileMaker before this function runs, so
// queryIfTrue should be built from the same query object passed as the first param.
// Example:
//   QueryWhen (
//     q ;
//     not IsEmpty ( filterVal ) ;
//     QueryWhere ( q ; MyTable::status ; "=" ; filterVal )
//   )
If ( condition ; queryIfTrue ; query )

// Returns JSONGetElement( json ; property ) where property is resolved from
// the field argument using this priority order:
//   1. GetFieldName( field ) — works when field is a real FM field reference;
//      strips the table occurrence prefix (everything before ::)
//   2. field contains :: — strips the table prefix from the string value
//   3. Fallback — assumes field is already the intended property name string
// If index is provided (non-empty), JSONGetElement( json ; index ) is evaluated
// first to extract an array element, and the property lookup runs on that result.
// Returns "?" if the working JSON does not pass JSON validation.
Let
(
[
_working = If ( not IsEmpty ( index ) ; JSONGetElement ( json ; index ) ; json ) ;
_isValidJson = not Exact ( Left ( JSONFormatElements ( _working ) ; 1 ) ; "?" ) ;
_fqName = GetFieldName ( field ) ;
_colonPos = Position ( field ; "::" ; 1 ; 1 ) ;
_property = Case (
	not IsEmpty ( _fqName ) and Position ( _fqName ; "::" ; 1 ; 1 ) > 0 ;
		Middle ( _fqName ; Position ( _fqName ; "::" ; 1 ; 1 ) + 2 ; Length ( _fqName ) ) ;
	not IsEmpty ( _fqName ) ;
		_fqName ;
	_colonPos > 0 ;
		Middle ( field ; _colonPos + 2 ; Length ( field ) ) ;
	// ELSE
	field
	)
];
Case (
	not _isValidJson ;
		"?" ;
	// ELSE
	JSONGetElement ( _working ; _property )
	)
)
